    public static void main(Args _args)
	{
        //boolean           ret;
        //str               desccaption;

        //FormRun formObject = _args.caller();
        //FormDataSource salesTable_ds= formObject.dataSource('SalesTable');
        //salesTable_ds.write();

        //if(formObject)
        //{
        //    #Task

        //    formObject.task(#taskRefresh);
        //}
        //if (_args.record().TableId != tableNum(SalesTable))
        //{
        //    throw error("Error workflow not processed");
        //}

        SalesTable salesTable = _args.record();

        WorkflowSubmitDialog workflowSubmitDialog = WorkflowSubmitDialog::construct(_args.caller().getActiveWorkflowConfiguration());
        workflowSubmitDialog.run();

        if (workflowSubmitDialog.parmIsClosedOK())
        {
            WorkflowComment comment = workflowSubmitDialog.parmWorkflowComment();

            try
            {
                ttsbegin;
                SalesTable::updateWorkflowStatus(salesTable.RecId, VersioningDocumentState::InReview);
                Workflow::activateFromWorkflowType(workflowTypeStr(ETGSalesOrderWFType), salesTable.RecId, comment, NoYes::No);
                ttscommit;
            }
            catch(exception::Error)
            {
                info("Error");
            }

            FormDataSource callerDS = FormDataUtil::getFormDataSource(_args.record());
            callerDS.refresh();
            callerDS.research(true);
            _args.caller().updateWorkflowControls();
        }
	}
